const token = $('Auth Siigo').first().json.access_token;
const SH = { Authorization:'Bearer '+token, 'Partner-Id':'n8nApp' };
const SB = 'https://wavqyesyqqmawjfaztvb.supabase.co';
const KEY = '<JWT_REDACTED>';
const H = { apikey:KEY, Authorization:'Bearer '+KEY };
const http = (o) => this.helpers.httpRequest(o);

const hoy = new Date();
const desde = new Date(hoy.getTime() - 75*86400000).toISOString().slice(0,10);
const hasta = hoy.toISOString().slice(0,10);

// 1. IDs en Supabase dentro de la ventana (por fecha de factura)
const sbIds = [];
let off = 0;
while (true) {
  const r = await http({ method:'GET', json:true, headers:H,
    url: SB + '/rest/v1/ventas_invoices?select=id&raw->>date=gte.' + desde + '&raw->>date=lte.' + hasta + '&limit=1000&offset=' + off });
  const arr = Array.isArray(r) ? r : [];
  for (const x of arr) sbIds.push(x.id);
  if (arr.length < 1000) break;
  off += 1000;
}

// 2. IDs vivos en Siigo (est�ndar + serie FV-2 exportaci�n)
const live = new Set();
async function fetchLive(extra) {
  const first = await http({ method:'GET', json:true, headers:SH,
    url: 'https://api.siigo.com/v1/invoices?date_start=' + desde + '&date_end=' + hasta + extra + '&page=1&page_size=100' });
  const tot = (first.pagination||{}).total_results || 0;
  const pages = Math.ceil(tot/100);
  for (const i of (first.results||[])) live.add(i.id);
  for (let p=2; p<=pages; p++) {
    const r = await http({ method:'GET', json:true, headers:SH,
      url: 'https://api.siigo.com/v1/invoices?date_start=' + desde + '&date_end=' + hasta + extra + '&page=' + p + '&page_size=100' });
    for (const i of (r.results||[])) live.add(i.id);
  }
}
await fetchLive('');
await fetchLive('&document_id=30537');

// 3. Candidatas: en Supabase pero no en la lista viva
const candidatas = sbIds.filter(id => !live.has(id));

// Cap de seguridad
if (candidatas.length > 60) {
  return [{ json: { alerta:'DEMASIADAS CANDIDATAS ('+candidatas.length+') - no se borr� nada', ventana:desde+'..'+hasta, sbCount:sbIds.length, liveCount:live.size } }];
}

// 4. Verificar cada candidata con GET directo ? borrar SOLO si 404
const borradas = [];
const conservadas = [];
for (const id of candidatas) {
  let existe = true; // fail-safe: solo se pone false ante un 404 confirmado
  try {
    await http({ method:'GET', json:true, headers:SH, url:'https://api.siigo.com/v1/invoices/' + id });
  } catch (e) {
    const code = e.httpCode || e.statusCode || (e.cause && e.cause.statusCode) || 0;
    if (String(code) === '404' || /\b404\b/.test(String(e.message||''))) existe = false;
  }
  if (!existe) {
    await http({ method:'DELETE', json:true, headers:Object.assign({}, H, { Prefer:'return=minimal' }),
      url: SB + '/rest/v1/ventas_invoices?id=eq.' + id });
    borradas.push(id);
  } else {
    conservadas.push(id);
  }
}

return [{ json: {
  ventana: desde + '..' + hasta,
  supabase: sbIds.length, vivas: live.size,
  candidatas: candidatas.length,
  borradas: borradas.length, idsBorradas: borradas,
  conservadas: conservadas.length
} }];
